mapper.update:
        UPDATE xeus.mt_dashbd_list SET
            mgr_seq = #{mgrSeq}::numeric


				, user_id = #{userId}



				, brd_title = #{brdTitle}



				, json_txt = #{jsonTxt}



				, mdfy_dat = #{mdfyDat}


        WHERE mgr_seq = #{mgrSeq}::numeric

mapper.select:
        SELECT (100-ROUND(100.*int_err.cnt/inf_total.cnt, 2))
		FROM
		(SELECT count(*) AS cnt FROM xeus.asset_status WHERE mgr_no LIKE 'INF%') AS int_err,
		(SELECT count(*) AS cnt FROM xeus.asset_infra


                	AND use_yn = #{useYn}


		) AS inf_total
